CREATE PROC [dbo].[DQT_PALLET_CHITIET_INSERT]
(
	@id uniqueidentifier, 
	@pallet_id int, 
	@id_nguyenlieu nvarchar(50),
	@xuatxu int, 
	@dayy float, 
	@rong float, 
	@dai float, 
	@sothanh int, 
	@sokhoi float,
	@ngaytao datetime, 
	@nguoitao nvarchar(50), 
	@ngaysua datetime, 
	@nguoisua nvarchar(50),
	@active bit,
	@dain bit = 0,
	@ngayin datetime = NULL,
	@sophieu nvarchar(50) OUT,
	@donhang nvarchar(200) = NULL,
	@phanloai nvarchar(50) = NULL,
	@ghichu nvarchar(max) = NULL,
	@fsc_id int = NULL,
	@ngaysanxuat date = NULL,
	@malo_nguyenlieu nvarchar(50) = NULL,
	@dvt nvarchar(50) = NULL,
	@congdoan nvarchar(50) = NULL,
	@machatluong nvarchar(50) = NULL
)
AS
BEGIN
	SET @sophieu = CAST(ABS(CAST(CRYPT_GEN_RANDOM(8) AS bigint)) AS varchar(20));
	WHILE 1 = 1
	BEGIN
		IF EXISTS (SELECT 1 FROM dqt_pallet_chitiet WHERE sophieu = @sophieu)
		BEGIN
			SET @sophieu = CAST(ABS(CAST(CRYPT_GEN_RANDOM(8) AS bigint)) AS varchar(20));
		END
		ELSE
		BEGIN
			BREAK;
		END
	END

	INSERT INTO dqt_pallet_chitiet
	(
		id, 
		pallet_id, 
		id_nguyenlieu,
		xuatxu, 
		dayy, 
		rong, 
		dai, 
		sothanh, 
		sokhoi,
		ngaytao, 
		nguoitao, 
		ngaysua, 
		nguoisua,
		active,
		dain, 
		ngayin, 
		sophieu, 
		donhang,
		phanloai,
		ghichu,
		fsc_id, ngaysanxuat,
		malo_nguyenlieu,
		dvt,
		congdoan,
		machatluong
	)
	VALUES
	(
		@id, 
		@pallet_id, 
		@id_nguyenlieu,
		@xuatxu, 
		@dayy, 
		@rong, 
		@dai, 
		@sothanh, 
		@sokhoi,
		@ngaytao, 
		@nguoitao, 
		@ngaysua, 
		@nguoisua,
		@active,
		@dain, 
		@ngayin, 
		@sophieu, 
		@donhang,
		@phanloai,
		@ghichu,
		@fsc_id, @ngaysanxuat,
		@malo_nguyenlieu,
		@dvt,
		@congdoan,
		@machatluong
	)
	
END
